import json

# Load data
funding_file = locals()['var_function-call-12998690230637064644']
with open(funding_file, 'r') as f:
    funding_data = json.load(f)

capital_funded_projects = []
for row in funding_data:
    name = row.get('Project_Name', '').strip()
    if not name:
        continue
    if '(FEMA' in name or '(CalOES' in name or '(CalJPIA' in name:
        continue
    capital_funded_projects.append(name)

docs_file = locals()['var_function-call-12998690230637064277']
with open(docs_file, 'r') as f:
    docs_data = json.load(f)

design_projects = set()

for doc in docs_data:
    text = doc.get('text', '')
    if not text:
        continue
    lines = text.split(chr(10))
    in_design_section = False
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if 'Capital Improvement Projects (Design)' in line:
            in_design_section = True
            i += 1
            continue
        if in_design_section:
            if 'Capital Improvement Projects (' in line and '(Design)' not in line:
                in_design_section = False
                break
            if 'Disaster Recovery Projects' in line:
                in_design_section = False
                break
            if line:
                is_project = False
                for k in range(1, 6):
                    if i + k < len(lines):
                        next_line = lines[i+k].strip()
                        if 'Updates:' in next_line or 'Project Description:' in next_line or '(cid:190)' in next_line:
                            is_project = True
                            break
                if is_project:
                    if 'Page' not in line and 'Agenda' not in line:
                        design_projects.add(line)
        i += 1

# Identify matched
matches = set()
for dp in design_projects:
    if dp in capital_funded_projects:
        matches.add(dp)

# Fuzzy match the rest
unmatched_design = design_projects - matches
fuzzy_matches = []

def get_tokens(s):
    # simple tokenization
    return set(s.lower().replace('&', '').split())

for dp in unmatched_design:
    best_match = None
    best_score = 0
    dp_tokens = get_tokens(dp)
    if not dp_tokens: continue

    for fp in capital_funded_projects:
        fp_tokens = get_tokens(fp)
        intersection = dp_tokens.intersection(fp_tokens)
        score = len(intersection) / len(dp_tokens.union(fp_tokens)) # Jaccard
        if score > 0.4: # Threshold
            if score > best_score:
                best_score = score
                best_match = fp

    if best_match:
        fuzzy_matches.append((dp, best_match, best_score))

print('__RESULT__:')
print(json.dumps({
    'exact_matches': list(matches),
    'fuzzy_matches': fuzzy_matches,
    'count_exact': len(matches),
    'count_fuzzy': len(fuzzy_matches)
}))

